module RefModule(P, G, CI, CO);parameter WIDTH = 1; 
 input [WIDTH-1:0] P; 
 input [WIDTH-1:0] G; 
 input CI; 
 output reg [WIDTH-1:0] CO; 
 integer obf_i; 
 always @* begin 
  CO = 'bx; 
  if (^{P, G, CI} !== 1'bx) begin 
  CO[0] = G[0] || (P[0] && CI); 
  for (obf_i = 1; obf_i < WIDTH; obf_i = obf_i+1) 
  CO[obf_i] = G[obf_i] || (P[obf_i] && CO[obf_i-1]); 
  end 
 end 
 endmodule
